const text = $json.text || $json.content || '';
const deal_id = $('Contract Webhook').item.json.body.deal_id;
const contract_type = $('Contract Webhook').item.json.body.contract_type || 'unknown';

// Split into chunks of 8000 words with 500-word overlap
const words = text.split(/\s+/);
const chunks = [];
const chunk_size = 8000;
const overlap = 500;

for (let i = 0; i < words.length; i += chunk_size - overlap) {
  chunks.push(words.slice(i, i + chunk_size).join(' '));
  if (i + chunk_size >= words.length) break;
}

// For now, process first chunk (covers most contracts up to ~60 pages)
return [{ json: { text_chunk: chunks[0] || text, deal_id, contract_type, total_chunks: chunks.length, char_count: text.length } }];

